            print(f"Length: {len(locals()[key])}")
            result = locals()[key]
            break
else:
    # If not in locals, check if it's a file path
    result = []
    for key, value in locals().items():
        if 'query_db' in key and isinstance(value, str) and value.endswith('.json'):
            try:
                with open(value, 'r') as f:
                    result = json.load(f)
                break
            except:
                pass

print("Result found:", len(result) if result else "No result")
