import json

articles = var_functions.query_db:18

sp_keywords = ['sport', 'game', 'match', 'player', 'team', 'championship', 'tournament', 'race']
sports = []

for a in articles:
    a['desc_len'] = len(a['description'])
    td = (a['title'] + ' ' + a['description']).lower()
    if any(k in td for k in sp_keywords):
        sports.append(a)

if sports:
    longest = max(sports, key=lambda x:x['desc_len'])
    result = {'title': longest['title'], 'length': longest['desc_len']}
else:
    result = {'error': 'No sports articles found'}

print('__RESULT__:')
print(json.dumps(result))

